/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Validates phone numbers, formats messages, and delivers via SmsTransport.
 *
 * NOTE: User preferences were designed with email-only in mind (see
 * src/models/user-preferences.ts). The preferences model and validator
 * need to be updated to support SMS preferences (enabled, frequency,
 * per-category toggles) before SMS preferences can be enforced.
 * See SMS_CHANNEL_NOTES.md for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsConfig {
  /** Sender phone number or short code */
  fromNumber: string;
  /** Maximum message length before truncation */
  maxLength: number;
}

export const defaultSmsConfig: SmsConfig = {
  fromNumber: '+10000000000',
  maxLength: 160,
};

/**
 * A formatted SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface for sending SMS messages.
 * Allows injecting a mock transport for testing.
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ accepted: boolean; error?: string }>;
}

/**
 * Default transport that simulates successful delivery (for use until
 * a real SMS provider like Twilio is integrated). Mirrors DefaultEmailTransport pattern.
 */
export class DefaultSmsTransport implements SmsTransport {
  private sentMessages: SmsMessage[] = [];

  async sendSms(message: SmsMessage): Promise<{ accepted: boolean; error?: string }> {
    this.sentMessages.push(message);
    return { accepted: true };
  }

  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }
}

const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

/**
 * Validates a phone number in E.164 format (e.g. +14155551234).
 */
export function isValidPhoneNumber(phone: string): boolean {
  return PHONE_REGEX.test(phone);
}

/**
 * Resolves the recipient phone number from the payload.
 * Checks metadata.recipientPhone first, then falls back to the recipient field.
 */
export function resolvePhoneNumber(payload: NotificationPayload): string | null {
  const metadataPhone = payload.metadata?.['recipientPhone'] as string | undefined;
  if (metadataPhone && isValidPhoneNumber(metadataPhone)) {
    return metadataPhone;
  }
  if (isValidPhoneNumber(payload.recipient)) {
    return payload.recipient;
  }
  return null;
}

/**
 * Formats a notification payload into an SMS message body.
 * Truncates to maxLength if needed.
 */
export function formatSmsBody(payload: NotificationPayload, maxLength: number): string {
  const text = `${payload.subject}: ${payload.body}`;
  if (text.length <= maxLength) {
    return text;
  }
  return text.substring(0, maxLength - 3) + '...';
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private config: SmsConfig;
  private transport: SmsTransport;

  constructor(config?: Partial<SmsConfig>, transport?: SmsTransport) {
    this.config = { ...defaultSmsConfig, ...config };
    this.transport = transport ?? new DefaultSmsTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const phone = resolvePhoneNumber(payload);

    if (!phone) {
      const msg = `Invalid phone number for SMS notification: "${payload.recipient}"`;
      this.logger.warn(msg);
      return { success: false, error: msg };
    }

    const body = formatSmsBody(payload, this.config.maxLength);

    const message: SmsMessage = {
      to: phone,
      from: this.config.fromNumber,
      body,
    };

    try {
      const result = await this.transport.sendSms(message);

      if (result.accepted) {
        this.logger.info(`SMS sent to ${phone}: "${payload.subject}"`);
        return { success: true };
      }

      const errorMsg = result.error ?? 'SMS rejected by transport';
      this.logger.warn(`SMS delivery failed for ${phone}: ${errorMsg}`);
      return { success: false, error: errorMsg };
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`SMS transport error for ${phone}: ${errorMsg}`);
      return { success: false, error: errorMsg };
    }
  }
}

